// EiaSeriesOptions is the resolver for the eiaSeriesOptions field.
func (r *queryResolver) EiaSeriesOptions(ctx context.Context) ([]*gqlmodel.EIASeriesOption, error) {
	if _, err := r.requirePermission(ctx, permission.ResourceFuelSurchargeProgram, permission.OpRead); err != nil {
		return nil, err
	}

	registry := fuelsurcharge.EIASeriesRegistry()
	options := make([]*gqlmodel.EIASeriesOption, 0, len(registry))
	for _, def := range registry {
		options = append(options, &gqlmodel.EIASeriesOption{
			SeriesID: def.SeriesID,
			Code:     def.Code,
			Name:     def.Name,
			Region:   def.Region,
			FuelType: def.FuelType,
		})
	}

	return options, nil
}
